function ModelGoldBuy:OnGoldBuyDetailResp(pb,ret)
    local goldItemList = self._goldItemList
    if not goldItemList then
        goldItemList = {}
        self._goldItemList = goldItemList
    end
    local items = pb.items
    local baseGold = pb.baseGold
    for i, v in ipairs(items) do
        local item = StructGoldBuy:New()
        item:CreateByPb(v)
        goldItemList[item.refId] = item
        if(item.refId==1)then
            self:SetCountDown(item)
        end
    end
end

