function ModelGoldBuy:GetBuyNeedItemIconByRefId(id)
    if not id then
        return
    end

    local goldBuyBasicsDate = self:GetGoldBuyBasicsRefById(id)
    local buyNeed = goldBuyBasicsDate.buyNeed

    if buyNeed and buyNeed ~= "" then
        local strList = string.split(buyNeed,",")
        local buyNeedStr = string.split(strList[1],"=")

        if #buyNeedStr > 0 and buyNeedStr[1] and buyNeedStr[1] ~= "" then
            return gModelItem:GetItemImgByRefId(buyNeedStr[1])
        end
    end
    return
end

--当前档位需要花费货币的数量
function ModelGoldBuy:GetBuyNeedCountByRefId(id,remainTime,maxTime,buyTime)
    if not id then
        return
    end

    local index = buyTime and buyTime or maxTime - remainTime + 1
    local goldBuyBasicsDate = self:GetGoldBuyBasicsRefById(id)
    local buyNeed = goldBuyBasicsDate.buyNeed

    if buyNeed and buyNeed ~= "" then
        local strList = string.split(buyNeed,",")
        index = index > #strList and #strList or index
        local buyNeedStr = string.split(strList[index],"=")

        if #buyNeedStr > 0 and buyNeedStr[2] and buyNeedStr[2] ~= "" then
            return buyNeedStr[2]
        end
    end
end
------------------------------------------------------------------------
function ModelGoldBuy:SetCountDown(item)
    if not self._timer then
        self._timer = LxTimer:New()
    end
    self._timer:TimerRemoveByKey(self._countDown)
    self._nextResetTime = tonumber(item.nextResetTime)
    local curTime = GetTimestamp()
    local time = self._nextResetTime - curTime
    if(time<=0)then
        return
    end
    self._timer:TimerCreate(self._countDown,function(...) self:OnCountDown(...) end, time, false, 1)
end

function ModelGoldBuy:OnCountDown(key)--冷却计时
    self._timer:TimerRemoveByKey(key)
    local curTime = GetTimestamp()
    local time = self._nextResetTime - curTime
    if(time>0)then
        self._timer:TimerCreate(key, function(...) self:OnCountDown(...) end, time, false, 1)
        return
    end
    gModelRedPoint:ShowPointRed(14700000,true)
end
--清理工作
--停止计时器之类的
function ModelGoldBuy:OnModelClear()
    local timer = self._timer
    if timer then
        timer:Destroy()
        self._timer = nil
    end
end

return ModelGoldBuy